import React from "react";
import { NavLink } from "react-router-dom";
import styleLinc from "./Link.module.css";

const Link = (props) => {
  return (
    <nav>
      <div className={styleLinc.container}>
        <NavLink
          to={props.to}
          className={(navData) => (navData.isActive ? "active-style" : "none")}
        >
          {props.text}
        </NavLink>
      </div>
    </nav>
  );
};

export default Link;
